public void updateProductDescriptionSafe(Connection conn, int productId, String newDescription) throws SQLException {
    String sql = "UPDATE products SET description = ? WHERE id = ?";

    try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
        pstmt.setString(1, newDescription);
        pstmt.setInt(2, productId);

        int rowsAffected = pstmt.executeUpdate();

        SQLWarning warning = pstmt.getWarnings();   // ✅ FIXED : Check for warnings immediately after execution
        while (warning != null) {
            // Log the specific issue (e.g., "Data truncation")
            System.err.println("SQL Warning:");
            System.err.println("  Message: " + warning.getMessage());
            System.err.println("  SQLState: " + warning.getSQLState());
            System.err.println("  VendorCode: " + warning.getErrorCode());

            // Warnings can be chained; ensure we get all of them
            warning = warning.getNextWarning();
        }

        System.out.println("Update complete. Rows affected: " + rowsAffected);
    }
}

